#!/usr/bin/env python3"""Valida que o banco Supabase tem TODAS as tabelas, colunas, constraints,Ã­ndices e funÃ§Ãµes esperadas pelas migrations.Sempre usa REST API (RPC exec_sql_query) para ser compatÃ­vel com CI/CD."""import osimport sysfrom pathlib import Pathfrom dotenv import load_dotenvfrom supabase import create_clientload_dotenv(Path(__file__).resolve().parent.parent / ".env")EXPECTED_TABLES = [    "prices",    "price_history",    "review_queue",    "scraping_logs",    "stores",    "flyers",    "ingredients",    "schedules",    "scrape_frequencies",    "alert_recipients",    "alert_rules",    "feature_flags",    "recipes",    "recipe_items",]EXPECTED_COLUMNS = {    "prices": [        "id",        "ingredient_id",        "store_id",        "source",        "store_name",        "raw_product",        "raw_price",        "raw_unit",        "collected_at",        "valid_from",        "valid_until",        "validity_raw",        "collected_weekday",        "is_promotion",        "tier",        "confidence",        "normalized",        "city",        "logistics",        "brand",        "price_per_kg",    ],    "review_queue": [        "id",        "raw_product",        "raw_price",        "raw_unit",        "store_name",        "source",        "confidence",        "suggestions",        "validity_raw",        "status",        "resolved_ingredient",        "collected_at",        "reviewed_at",        "brand",        "image_url",        "source_url",        "match_reason",        "match_type",        "top3",    ],    "ingredients": [        "id",        "canonical_name",        "category",        "aliases",        "unit_target",        "active",        "created_at",        "updated_at",        "brands",        "search_terms",    ],    "recipes": [        "id",        "name",        "yield_qty",        "overhead_pct",        "profit_pct",        "created_at",    ],    "recipe_items": [        "id",        "recipe_id",        "ingredient_id",        "quantity_g",        "selected_store",        "price_per_kg",    ],}EXPECTED_CONSTRAINTS = {    "prices": ["prices_ingredient_id_store_id_collected_at_key"],    "price_history": ["price_history_ingredient_id_store_id_collected_at_key"],}EXPECTED_INDEXES = [    "idx_prices_ing_collected",    "idx_history_ing_collected",    "idx_review_collected",    "idx_stores_name",    "idx_logs_store_started",    "idx_recipe_items_recipe",    "idx_prices_price_per_kg",  # generated column index    "idx_prices_promo_collected",  # partial index    "idx_prices_store_collected",  # FK index    "idx_review_status_collected",  # review queue filter    "idx_flyers_store_ocr_collected",  # flyer filter    "idx_ingredients_active_name",  # active filter]EXPECTED_FUNCTIONS = ["upsert_price_rpc", "cleanup_old_prices", "cleanup_old_logs", "cleanup_old_flyers"]def get_client():    url = os.environ.get("SUPABASE_URL", "")    key = os.environ.get("SUPABASE_SERVICE_ROLE_KEY", "")    if not url or not key:        print("ERROR: SUPABASE_URL and SUPABASE_SERVICE_ROLE_KEY must be set")        sys.exit(1)    return create_client(url, key)def run_query(client, sql):    """Executes SQL via the exec_sql_query RPC."""    try:        # The RPC returns the result as a list of rows (dicts)        res = client.rpc("exec_sql_query", {"sql": sql}).execute()        return res.data if res.data else []    except Exception as e:        print(f"  Query Failed: {sql}\n  Error: {e}")        return Nonedef validate_tables(client):    print("=== TABLES ===")    sql = "SELECT table_name FROM information_schema.tables WHERE table_schema = 'public' ORDER BY table_name"    db_tables = {r["table_name"] for r in run_query(client, sql)} if run_query(client, sql) is not None else set()    ok = 0    for t in EXPECTED_TABLES:        if t in db_tables:            print(f"  [OK] {t}")            ok += 1        else:            print(f"  [!!] {t} MISSING")    extra = db_tables - set(EXPECTED_TABLES)    if extra:        print(f"  [--] Extras: {', '.join(sorted(extra))}")    return ok, len(EXPECTED_TABLES)def validate_columns(client):    print("\n=== COLUMNS ===")    ok, total = 0, 0    for table, expected in EXPECTED_COLUMNS.items():        sql = f"SELECT column_name FROM information_schema.columns WHERE table_schema = 'public' AND table_name = {repr(table)} ORDER BY ordinal_position"  # noqa: S608        db_cols = {r["column_name"] for r in run_query(client, sql)} if run_query(client, sql) is not None else set()        for col in expected:            total += 1            if col in db_cols:                ok += 1            else:                print(f"  [-] {table}.{col} MISSING")    print(f"  {ok}/{total} columns OK")    return ok, totaldef validate_constraints(client):    print("\n=== CONSTRAINTS ===")    ok, total = 0, 0    for table, names in EXPECTED_CONSTRAINTS.items():        for cname in names:            total += 1            sql = f"SELECT 1 FROM pg_constraint WHERE conrelid = {repr(table)}::regclass AND conname = {repr(cname)}"  # noqa: S608            if run_query(client, sql):                print(f"  [OK] {table}: {cname}")                ok += 1            else:                print(f"  [-] {table}: {cname} MISSING")    return ok, totaldef validate_indexes(client):    print("\n=== INDEXES ===")    ok = 0    for idx in EXPECTED_INDEXES:        sql = f"SELECT 1 FROM pg_indexes WHERE indexname = {repr(idx)}"  # noqa: S608        if run_query(client, sql):            print(f"  [OK] {idx}")            ok += 1        else:            print(f"  [-] {idx} MISSING")    return ok, len(EXPECTED_INDEXES)def validate_functions(client):    print("\n=== FUNCTIONS ===")    ok = 0    for fn in EXPECTED_FUNCTIONS:        sql = f"SELECT 1 FROM pg_proc WHERE proname = {repr(fn)}"  # noqa: S608        if run_query(client, sql):            print(f"  [OK] {fn}()")            ok += 1        else:            print(f"  [-] {fn}() MISSING")    return ok, len(EXPECTED_FUNCTIONS)def main():    client = get_client()    results = []    results.append(validate_tables(client))    results.append(validate_columns(client))    results.append(validate_constraints(client))    results.append(validate_indexes(client))    results.append(validate_functions(client))    total_ok = sum(o for o, _ in results)    total_exp = sum(t for _, t in results)    print(f"\n{'=' * 40}")    print(f"RESULT: {total_ok}/{total_exp} checks passed")    if total_ok == total_exp:        print("ALL PHASES VERIFIED [OK]")    else:        print("SOME PHASES MISSING [FAIL]")        sys.exit(1)if __name__ == "__main__":    main()